import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import Navbar from '../../components/Navbar';
import Footer from '../../components/Footer';
import PropertyCard from '../../components/PropertyCard';
import API from '../../services/api';
import './Home.css';

const Home = () => {
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(true);
  const [scrollY, setScrollY] = useState(0);
  const [searchFilters, setSearchFilters] = useState({
    city: '',
    propertyType: '',
    minPrice: '',
    maxPrice: ''
  });

  useEffect(() => {
    fetchProperties();
    
    // Parallax scroll effect
    const handleScroll = () => {
      setScrollY(window.scrollY);
    };
    
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const fetchProperties = async (filters = {}) => {
    try {
      setLoading(true);
      const queryParams = new URLSearchParams(filters).toString();
      const response = await API.get(`/properties?${queryParams}`);
      setProperties(response.data.data);
    } catch (error) {
      console.error('Error fetching properties:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    fetchProperties(searchFilters);
  };

  const handleFilterChange = (e) => {
    setSearchFilters({
      ...searchFilters,
      [e.target.name]: e.target.value
    });
  };

  return (
    <div className="home">
      <Navbar />

      {/* Hero Section with Parallax */}
      <section className="hero-parallax">
        <div 
          className="hero-bg" 
          style={{ transform: `translateY(${scrollY * 0.5}px)` }}
        ></div>
        
        <div className="hero-overlay"></div>
        
        <div className="hero-content" style={{ transform: `translateY(${scrollY * 0.3}px)` }}>
          <div className="hero-badge">
            <span className="badge-icon">✨</span>
            Premium Real Estate
          </div>
          
          <h1 className="hero-title">
            Discover Your
            <span className="gradient-text"> Dream Property</span>
          </h1>
          
          <p className="hero-subtitle">
            Luxury homes and exclusive properties in prime locations
          </p>

          {/* Enhanced Search Box with Glass Effect */}
          <div className="search-container glass-effect">
            <form className="search-form" onSubmit={handleSearch}>
              <div className="search-input-group">
                <span className="input-icon">📍</span>
                <input
                  type="text"
                  name="city"
                  placeholder="Location / City"
                  className="search-input"
                  value={searchFilters.city}
                  onChange={handleFilterChange}
                />
              </div>

              <div className="search-input-group">
                <span className="input-icon">🏠</span>
                <select
                  name="propertyType"
                  className="search-input"
                  value={searchFilters.propertyType}
                  onChange={handleFilterChange}
                >
                  <option value="">Property Type</option>
                  <option value="House">House</option>
                  <option value="Apartment">Apartment</option>
                  <option value="Villa">Villa</option>
                  <option value="Condo">Condo</option>
                  <option value="Commercial">Commercial</option>
                </select>
              </div>

              <div className="search-input-group">
                <span className="input-icon">💰</span>
                <input
                  type="number"
                  name="minPrice"
                  placeholder="Min Price"
                  className="search-input"
                  value={searchFilters.minPrice}
                  onChange={handleFilterChange}
                />
              </div>

              <div className="search-input-group">
                <span className="input-icon">💎</span>
                <input
                  type="number"
                  name="maxPrice"
                  placeholder="Max Price"
                  className="search-input"
                  value={searchFilters.maxPrice}
                  onChange={handleFilterChange}
                />
              </div>

              <button type="submit" className="btn-search-premium">
                <span>Search</span>
                <span className="search-icon">🔍</span>
              </button>
            </form>
          </div>

          {/* Scroll Indicator */}
          <div className="scroll-indicator">
            <div className="mouse"></div>
            <p>Scroll to explore</p>
          </div>
        </div>
      </section>

      {/* Featured Properties with 3D Cards */}
      <section className="properties-section">
        <div className="container">
          <div className="section-header">
            <span className="section-badge">Featured</span>
            <h2 className="section-title">
              Luxury Properties
              <span className="title-underline"></span>
            </h2>
            <p className="section-subtitle">
              Handpicked premium properties for discerning buyers
            </p>
          </div>

          {loading ? (
            <div className="loading-state">
              <div className="loader"></div>
              <p>Discovering amazing properties...</p>
            </div>
          ) : properties.length === 0 ? (
            <div className="empty-state">
              <div className="empty-icon">🏘️</div>
              <h3>No properties available</h3>
              <p>Check back soon for new listings</p>
            </div>
          ) : (
            <div className="property-grid-3d">
              {properties.map((property, index) => (
                <div 
                  key={property._id} 
                  className="property-card-wrapper"
                  style={{ animationDelay: `${index * 0.1}s` }}
                >
                  <PropertyCard property={property} />
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* Stats Section with Counter Animation */}
      <section className="stats-section">
        <div className="container">
          <div className="stats-grid">
            <div className="stat-item">
              <div className="stat-number" data-count="500">500+</div>
              <div className="stat-label">Properties Listed</div>
            </div>
            <div className="stat-item">
              <div className="stat-number" data-count="200">200+</div>
              <div className="stat-label">Happy Clients</div>
            </div>
            <div className="stat-item">
              <div className="stat-number" data-count="50">50+</div>
              <div className="stat-label">Expert Agents</div>
            </div>
            <div className="stat-item">
              <div className="stat-number" data-count="15">15+</div>
              <div className="stat-label">Years Experience</div>
            </div>
          </div>
        </div>
      </section>

      {/* Features with 3D Cards */}
      <section className="features-section-3d">
        <div className="container">
          <div className="section-header">
            <span className="section-badge">Why Choose Us</span>
            <h2 className="section-title">
              Premium Services
              <span className="title-underline"></span>
            </h2>
          </div>

          <div className="features-grid-3d">
            <div className="feature-card-3d">
              <div className="feature-icon-3d">
                <span>🔍</span>
              </div>
              <h3>Smart Search</h3>
              <p>AI-powered property search with advanced filters</p>
            </div>

            <div className="feature-card-3d">
              <div className="feature-icon-3d">
                <span>🏆</span>
              </div>
              <h3>Premium Listings</h3>
              <p>Verified luxury properties from trusted agents</p>
            </div>

            <div className="feature-card-3d">
              <div className="feature-icon-3d">
                <span>💼</span>
              </div>
              <h3>Expert Guidance</h3>
              <p>Professional consultation from industry experts</p>
            </div>

            <div className="feature-card-3d">
              <div className="feature-icon-3d">
                <span>🔒</span>
              </div>
              <h3>Secure Deals</h3>
              <p>Safe and transparent transaction process</p>
            </div>
          </div>
        </div>
      </section>

      {/* CTA Section with Parallax */}
      <section className="cta-section-parallax">
        <div className="cta-bg" style={{ transform: `translateY(${scrollY * 0.2}px)` }}></div>
        <div className="cta-content">
          <h2>Ready to Find Your Dream Home?</h2>
          <p>Join thousands of satisfied homeowners who found their perfect property with us</p>
          <div className="cta-buttons">
            <Link to="/register" className="btn-cta-primary">Get Started</Link>
            <Link to="/properties" className="btn-cta-secondary">Browse Properties</Link>
          </div>
        </div>
      </section>

      <Footer />

      {/* Floating Action Button */}
      <div className="floating-chat">
        <div className="chat-icon">💬</div>
        <span className="chat-tooltip">Need Help?</span>
      </div>
    </div>
  );
};

export default Home;
